colsdata.lang:
// BO columns
/*
   { data: "ort" },
   { data: "kanton" },
   { data: "name" },
   { data: "baujahr" },
   { data: "konfession" },
   { data: "bautypus" },
   { data: "adresse" },
   { data: "architekt" },
   { data: "infolink" }
*/
columns: [
    { data: "ort",
        render: function (data, type, row) {
	        return data.toString();
        }
    },
    { data: "kanton",
        render: function (data, type, row) {
            return data.toString();
        }
    },
    { data: "name",
        render: function (data, type, row) {
            infolink = row['infolink'].toString();
			linktext = data.toString();
			if (infolink.length > 1) {
				linktext = "<a href='" + infolink + "'>" + linktext + "</a>";	
			}
			return linktext;
        }
    },
    { data: "baujahr",
        render: function (data, type, row) {
            return data.toString();
        }
    },
    { data: "konfession",
        render: function (data, type, row) {
            return data.toString();
        }
    },
    { data: "bautypus",
        render: function (data, type, row) {
            return data.toString();
        }
    },
    { data: "architekt",
        render: function (data, type, row) {
            return data.toString();
        }
    }
],
lengthMenu: [ [25, 50, 100, -1], [25, 50, 100, "Alle"] ], //change paging choice
// https://datatables.net/examples/api/multi_filter_select.html
initComplete: function () {
    i = 0;
    this.api().columns().every(function() {
        var column = this;
        var column_filter_for = [1,4,5,6]; // columns filtering by Kanton, Konfession, Bautypus, Architekt
        if (column_filter_for.includes(i)) {
			let select = document.createElement('select');
			select.add(new Option(''));
			column.header().appendChild(select);

			// Apply listener for user change in value
			select.addEventListener('change', function () {
				var val = DataTable.util.escapeRegex(select.value);
				column
					.search(val ? '^' + val + '$' : '', true, false)
					.draw();
			});

			// Add list of options
			column
				.data()
				.unique()
				.sort()
				.each(function (d, j) {
					if (d != '') {
					    select.add(new Option(d));    
					}
            });
		}
        else {
            column.text = '';
        }
        i++;
    });
},
// Translation
dom: '<lf<t>ip>',
    language: {
        "search": "Suchen:",
		"info": "Seite _PAGE_ von _PAGES_",
		"lengthMenu":     "Zeige _MENU_ Einträge",
		"zeroRecords":    "Keine Einträge gefunden",
		"paginate": {
			"first":      "Erster",
			"last":       "Letzter",
			"next":       "Weiter",
			"previous":   "Zurück"
		}	
    }
// EO columns

// BO columnDefs
columnDefs: [
    { orderable: false, targets: [4,5,6] }
	//{ width: "15%", targets: 5,6 }
]
// EO columnDefs

// BO processCustomJS
//Popup
function processCustomJS(table) {
}
// EO processCustomJS

